texttool_globals_dialog_message___add_shortcut_message = TextObject(bs_BA="Dodati prečicu za pregled aplikacije?", cs_CZ="Přidat zkratku do přehledu aplikací?", da_DK="Tilføj genvej til appoversigt?", de_DE="Shortcut zu App-Übersicht hinzufügen?", el_GR="Να προστεθεί συντόμευση προς την επισκόπηση των εφαρμογών;", en_GB="Add shortcut to app overview?", es_ES="¿Añadir atajo a la aplicación?", fi_FI="Lisätäänkö sovellusten yleiskuvan pikavalinta?", fr_FR="Ajouter un raccourci vers la vue d'ensemble des applications?", hr_HR="Dodati prečac za pregled aplikacija?", hu_HU="Parancsikon hozzáadása az alkalmazásáttekintéshez?", it_IT="Aggiungere shortcut alla panoramica app?", nl_NL="Shurtcut naar app-overzicht toevoegen?", no_NO="Legge snarvei til appoversikten?", pl_PL="Dodać skrót do przeglądu aplikacji?", pt_PT="Introduzir atalho para apresentação da app?", ro_RO="Adăugare comandă rapidă la prezentare generală aplicaţii?", ru_RU="Добавить ярлык в обзор приложений?", sk_SK="Pridať Shortcut k prehľadu aplikácií?", sl_SI="Ali želite dodati bližnjico za pregled aplikacij?", sr_RS="Dodati prečicu za pregled aplikacija?", sv_SE="Lägg till genväg till appöversikten?", tr_TR="Kısayol uygulamalara genel bakışa eklensin mi?", uk_UA="Додати ярлик в огляд додатків?")
texttool_globals_dialog_message___app_grid__confirm_display_dialog__message_app_already_on_center_display = TextObject(bs_BA="%1 je trenutno aktivan u MMI i ne može se koristiti istovremeno na\noba displeja. Želite li ovdje otvoriti aplikaciju?", cs_CZ="%1 je aktuálně aktivní v MMI a nelze používat současně na obou\ndisplejích. Chcete zde otevřít aplikaci?", da_DK="%1 p.t. aktiv i MMI og kan ikke anvendes samtidig i begge displays.\nVil du åbne appen her?", de_DE="%1 ist aktuell im MMI aktiv und kann nicht gleichzeitig auf beiden\nDisplays verwendet werden. Möchtest du die App hier öffnen?", el_GR="O/H/Το %1 είναι τώρα ενεργός/-ή/-ό στο MMI και δεν μπορεί να\nχρησιμοποιηθεί ταυτόχρονα και στις δύο οθόνες. Θέλετε να ανοίξετε εδώ την\nεφαρμογή;", en_GB="%1 is currently active on the MMI and cannot be used on both\ndisplays at the same time. Would you like to open the app here?", es_ES="La aplicación %1 está activa en el MMI y no se puede utilizar\nsimultáneamente en las dos pantallas. ¿Desea abrir la App aquí?", fi_FI="%1 on tällä hetkellä aktiivisena MMI:ssä eikä sitä voi käyttää\nsamanaikaisesti molemmilla näytöillä. Haluatko avata sovelluksen tähän?", fr_FR="L'application %1 est actuellement utilisée dans le MMI et ne peut\npas être utilisée simultanément sur les deux écrans. Souhaitez-vous ouvrir\nl'application ici?", hr_HR="Aplikacija %1 trenutačno je aktivna u MMI-ju i ne može se koristiti\nistovremeno na oba zaslona. Želite li aplikaciju otvoriti tu?", hu_HU="%1 jelenleg aktív az MMI-ben, és nem lehet egyszerre használni\nminkét kijelzőn. Meg szeretnéd itt nyitni az alkalmazást?", it_IT="Al momento l'app %1 è attiva nell'MMI e non può essere utilizzata\ncontemporaneamente su entrambi i display. Aprire qui l'app?", nl_NL="%1 is momenteel in MMI actief en kan niet tegelijkertijd op beide\ndisplays worden gebruikt. Wil je de app hier openen?", no_NO="%1 brukes i MMI nå og kan ikke brukes på begge displayene\nsamtidig. Vil du åpne appen her?", pl_PL="%1 jest obecnie aktywna w MMI i nie można z niej korzystać na obu\nwyświetlaczach. Czy chcesz otworzyć aplikację tutaj?", pt_PT="%1 está atualmente ativo no MMI e não pode ser utilizado em\nsimultâneo nos dois ecrãs. Queres abrir aqui a aplicação?", ro_RO="%1 este momentan activ în MMI şi nu poate fi utilizat simultan pe\nambele afişaje. Doriţi să deschideţi aici aplicaţia?", ru_RU="%1 в настоящее время активно в MMI и не может использоваться\nна обоих дисплеях одновременно. Хотите открыть приложение здесь?", sk_SK="%1 je momentálne aktívny v systéme MMI a nie je možné ho použiť\nna oboch displejoch súčasne. Chcete aplikáciu otvoriť tu?", sl_SI="Aplikacija %1 je trenutno aktivna v sistemu MMI in je ni mogoče\nistočasno uporabljati na obeh zaslonih. Ali želite aplikacijo odpreti tukaj?", sr_RS="%1 je trenutno aktivan u MMI i ne može se koristiti istovremeno na\noba displeja. Da li želite da otvorite aplikaciju ovde?", sv_SE="%1 är aktiv i MMI och kan inte användas samtidigt på båda\ndisplayer. Vill du öppna appen här?", tr_TR="%1 şu anda MMI'da aktif ve aynı anda her iki ekranda kullanılamaz.\nUygulamayı burada açmak ister misin?", uk_UA="%1 наразі активна у MMI і не може використовуватися на обох\nдисплеях одночасно. Хочете відкрити програму тут?")
texttool_globals_dialog_message___app_grid__confirm_display_dialog__message_app_already_on_passenger_display = TextObject(bs_BA="%1 je trenutno aktivan u MMI displeju suvozača i ne može se\nkoristiti istovremeno na oba displeja. Želite li ovdje otvoriti aplikaciju?", cs_CZ="%1 je aktuálně aktivní na displeji MMI spolujezdce a nelze používat\nsoučasně na obou displejích. Chcete zde otevřít aplikaci?", da_DK="%1 p.t. aktiv på MMI-display til forsædepassager og kan ikke\nanvendes samtidig i begge displays. Vil du åbne appen her?", de_DE="%1 ist aktuell im MMI Beifahrerdisplay aktiv und kann nicht\ngleichzeitig auf beiden Displays verwendet werden. Möchtest du die App hier\nöffnen?", el_GR="O/H/Το %1 είναι τώρα ενεργός/-ή/-ό στην οθόνη συνοδηγού του MMI\nκαι δεν μπορεί να χρησιμοποιηθεί ταυτόχρονα και στις δύο οθόνες. Θέλετε να\nανοίξετε εδώ την εφαρμογή;", en_GB="%1 is currently active on the MMI front passenger display and\ncannot be used on both displays at the same time. Would you like to open the app\nhere?", es_ES="La aplicación %1 está activa en la pantalla del MMI del\nacompañante y no se puede utilizar simultáneamente en las dos pantallas. ¿Desea\nabrir la App aquí?", fi_FI="%1 on tällä hetkellä aktiivisena MMI:n etumatkustajan näytöllä eikä\nsitä voi käyttää samanaikaisesti molemmilla näytöillä. Haluatko avata sovelluksen\ntähän?", fr_FR="L'application %1 est actuellement utilisée sur l'écran MMI du\npassager avant et ne peut pas être utilisée simultanément sur les deux écrans.\nSouhaitez-vous ouvrir l'application ici?", hr_HR="Aplikacija %1 trenutačno je aktivna na suvozačevom zaslonu MMI-ja\ni ne može se koristiti istovremeno na oba zaslona. Želite li aplikaciju otvoriti tu?", hu_HU="%1 jelenleg aktív az MMI utaskijelzőn, és nem lehet egyszerre\nhasználni minkét kijelzőn Meg szeretnéd itt nyitni az alkalmazást?", it_IT="Al momento l'app %1 è attiva nell'MMI del display passeggero\nanteriore e non può essere utilizzata contemporaneamente su entrambi i display.\nAprire qui l'app?", nl_NL="%1 is momenteel in het MMI-bijrijdersdisplay actief en kan niet\ntegelijkertijd op beide displays worden gebruikt. Wil je de app hier openen?", no_NO="%1 brukes på MMI-passasjerdisplayet nå og kan ikke brukes på\nbegge displayene samtidig. Vil du åpne appen her?", pl_PL="%1 jest obecnie aktywna na ekranie MMI pasażera i nie można z niej\nkorzystać na obu wyświetlaczach. Czy chcesz otworzyć aplikację tutaj?", pt_PT="%1 está atualmente ativo no ecrã do passageiro do MMI e não pode\nser utilizado em simultâneo nos dois ecrãs. Queres abrir aqui a aplicação?", ro_RO="%1 este momentan activ în afişajul MMI pasager faţă şi nu poate fi\nutilizat simultan pe ambele afişaje. Doriţi să deschideţi aici aplicaţia?", ru_RU="%1 в настоящее время активно на дисплее MMI переднего\nпассажира и не может использоваться на обоих дисплеях одновременно. Хотите\nоткрыть приложение здесь?", sk_SK="%1 je momentálne aktívny v systéme MMI na displeji spolujazdca a\nnie je možné ho použiť na oboch displejoch súčasne. Chcete aplikáciu otvoriť tu?", sl_SI="Aplikacija %1 je trenutno aktivna na sovoznikovem zaslonu sistema\nMMI in je ni mogoče istočasno uporabljati na obeh zaslonih. Ali želite aplikacijo\nodpreti tukaj?", sr_RS="%1 je trenutno aktivan na MMI displeju suvozača i ne može se\nkoristiti istovremeno na oba displeja. Da li želite da otvorite aplikaciju ovde?", sv_SE="%1 är aktiv på MMI-passagerardisplayen och kan inte användas\nsamtidigt på båda displayer. Vill du öppna appen här?", tr_TR="%1 şu anda MMI ön yolcu ekranında aktif ve aynı anda her iki\nekranda kullanılamaz. Uygulamayı burada açmak ister misin?", uk_UA="%1 наразі активна на дисплеї MMI переднього пасажира і не\nможе використовуватися на обох дисплеях одночасно. Хочете відкрити програму\nтут?")
texttool_globals_dialog_message___dashboard__navi_bought_later__message = TextObject(bs_BA="Da li za navigaciju treba dodati jednu pločicu na kontrolnoj tabli? (Napomena:\nPločica se postavlja na posljednja dva mjesta na kontrolnoj tabli.)", cs_CZ="Má se pro navigaci přidat dlaždice na dashboard? (Poznámka: Dlaždice se umístí na\nobě poslední místa dashboardu.)", da_DK="Skal der tilføjes en flade for navigationen på dashboardet? (Bemærk: Fladen\nplaceres på dashboardets sidste to steder.)", de_DE="Soll für die Navigation eine Kachel zum Dashboard hinzugefügt werden? (Hinweis:\nDie Kachel wird auf den letzten beiden Stellen des Dashboards platziert.)", el_GR="Να προστεθεί για την πλοήγηση ένα πλακίδιο στον πίνακα ελέγχου; (Υπόδειξη: Το\nπλακίδιο θα τοποθετηθεί στις τελευταίες δύο θέσεις του πίνακα ελέγχου.)", en_GB="Should a navigation tile be added to the dashboard? (Note: the tile will be placed\non the last two positions on the dashboard.)", es_ES="¿Añadir al panel de control un botón virtual para la navegación? (Nota: el botón\nvirtual aparecerá en las dos últimas posiciones del panel de control.)", fi_FI="Lisätäänkö kuvake kojelautaan navigointia varten? (Huomio: Kuvake sijoitetaan\nkojelaudan kahdelle viimeiselle paikalle.)", fr_FR="Est-ce qu'une icône doit être ajoutée au tableau de bord pour la navigation? (nota:\nl'icône sera placée sur les deux derniers emplacements du tableau de bord)", hr_HR="Treba li za navigaciju dodati pločicu na dashboardu (napomena: pločica će se\nsmjestiti na zadnja dva mjesta dashboarda.)", hu_HU="Hozzá szeretnél adni egy csempét az irányítópulthoz a navigáció számára?\n(Megjegyzés: a csempe az irányítópult utolsó két helyére kerül.)", it_IT="Aggiungere alla dashboard un riquadro per la navigazione? (Avvertenza: il riquadro\nviene posizionato sulle ultime due posizioni della dashboard.)", nl_NL="Moet voor de navigatie een tegel worden toegevoegd aan het dashboard?\n(opmerking: de tegel wordt op de laatste twee plekken van het dashboard\ngeplaatst.)", no_NO="Skal det legges til et ikon for navigasjon på skrivebordet? (Merk: Ikonet plasseres på\nde to siste plassene på skrivebordet.)", pl_PL="Czy dodać przycisk nawigacji na pulpicie? (Wskazówka: przycisk zostanie\numieszczony na ostatnich dwóch miejscach pulpitu).", pt_PT="Queres que introduza uma caixa do painel de bordo para a navegação? (Observação:\nA caixa será colocada nos dois últimos locais do painel de bordo.)", ro_RO="Să fie adăugată pentru navigaţie o casetă pe Dashboard? (indicaţie: caseta va fi\namplasată în ultimele două poziţii din Dashboard.)", ru_RU="Хотите добавить плитку на панель инструментов для навигации? (Примечание:\nплитка будет размещена на двух последних ячейках панели инструментов.)", sk_SK="Chcete pridať dlaždicu na Dashboard pre navigáciu? (Upozornenie: dlaždica bude\numiestnená na posledné dve miesta na Dashboarde.)", sl_SI="Ali želite za navigacijo dodati ploščico na nadzorni plošči? (Napotek: ploščica bo\nnameščena na zadnji dve mesti na nadzorni plošči.)", sr_RS="Da li treba dodati polje za navigaciju na kontrolnoj tabli? (Napomena: Polje će biti\npostavljeno na poslednja dva mesta kontrolne table.)", sv_SE="Vill du lägga till en panel på instrumentbrädan för navigering? (Observera: Panelen\nplaceras på de senaste båda ställena på instrumentbrädan.)", tr_TR="Navigasyon için gösterge paneline bir karo eklensin mi? (Not: Karo, gösterge\npanelinin son iki konumuna yerleştirilir.)", uk_UA="Хочете додати плитку на панель інструментів для навігації? (Примітка: плитка\nбуде розміщена на двох останніх місцях панелі інструментів.)")
texttool_globals_dialog_message___dashboard__tile__replace_confirmation_dialog__message = TextObject(bs_BA="Dodavanjem ove pločice se uklanja neka druga pločica. Zaista nastaviti?", cs_CZ="Přidání této dlaždice odstraní jinou dlaždici. Opravdu pokračovat?", da_DK="Tilføjelse af denne flade fjerner en anden flade. Vil du virkelig fortsætte?", de_DE="Das Hinzufügen dieser Kachel entfernt eine andere Kachel. Wirklich fortfahren?", el_GR="Με την προσθήκη αυτού του πλακιδίου θα αφαιρεθεί ένα άλλο πλακίδιο. Θέλετε\nσίγουρα να συνεχίσετε;", en_GB="Adding this tile will remove another tile. Continue anyway?", es_ES="Si añade este botón virtual, se eliminará otro. ¿Continuar igualmente?", fi_FI="Tämän kuvakkeen lisääminen poistaa jonkin toisen kuvakkeen. Haluatko varmasti\njatkaa?", fr_FR="L'ajout de cette icône entraînera la suppression d'une autre icône. Souhaitez-vous\nvraiment poursuivre?", hr_HR="Dodavanjem te pločice uklonit će se neka druga. Želite li uistinu nastaviti?", hu_HU="Ennek a csempének a hozzáadása eltávolít egy másik csempét. Biztosan folytatni\nszeretnéd?", it_IT="Aggiungendo questo riquadro verrà rimosso un altro riquadro. Procedere?", nl_NL="Met het toevoegen van deze tegel wordt een andere tegel verwijderd. Wil je echt\ndoorgaan?", no_NO="Hvis du legger til dette ikonet, vil et annet ikon bli fjernet. Er du sikker på at du vil\nfortsette?", pl_PL="Dodanie tego przycisku usunie inny przycisk. Czy na pewno kontynuować?", pt_PT="A introdução desta caixa origina a remoção de uma outra. Queres mesmo\ncontinuar?", ro_RO="Adăugarea acestei casete şterge o altă casetă. Doriţi într-adevăr să continuaţi?", ru_RU="Добавление этой плитки удалит другую плитку. Действительно продолжить?", sk_SK="Pridaním tejto dlaždice sa odstráni iná dlaždica. Skutočne chcete pokračovať?", sl_SI="Z dodajanjem te ploščice boste odstranili drugo ploščico. Ali res želite nadaljevati?", sr_RS="Dodavanjem ovog polja uklanjate drugo polje. Stvarno nastaviti?", sv_SE="Om du lägger panelen kommer en annan panel att tas bort. Vill du fortsätta?", tr_TR="Bu karonun eklenmesi başka bir karoyu kaldırır. Gerçekten devam edilsin mi?", uk_UA="Додавання цієї плитки видалить іншу плитку. Дійсно продовжити?")
texttool_globals_dialog_message___phone_missing_permissions_reason = TextObject(bs_BA="Kontrolnoj tabli su potrebna dodatna ovlaštenja za pristup telefonskim podacima.\nŽelite li sada dodijeliti ova ovlaštenja?", cs_CZ="Přístrojový panel vyžaduje další oprávnění pro přístup k údajům telefonu. Chcete\ntato oprávnění udělit nyní?", da_DK="Dashboardet kræver yderligere autorisationer for at kunne få adgang til\ntelefondataene. Vil du tildele disse autorisationer nu?", de_DE="Das Dashboard benötigt zusätzliche Berechtigungen, um auf die Telefondaten\nzugreifen zu können. Möchtest du diese Berechtigungen jetzt erteilen?", el_GR="Ο πίνακας ελέγχου χρειάζεται πρόσθετες εξουσιοδοτήσεις, ώστε να μπορεί να έχει\nπρόσβαση στα δεδομένα του τηλεφώνου. Θέλετε να χορηγήσετε τώρα αυτές τις\nεξουσιοδοτήσεις;", en_GB="The dashboard requires additional permissions to access telephone data. Do you\nwant to grant these permissions now?", es_ES="El panel de control precisa más permisos para acceder a los datos del teléfono.\n¿Desea conceder estos permisos ahora?", fi_FI="Kojelauta tarvitsee lisäoikeuksia puhelintietoihin pääsemiseksi. Haluatko myöntää\nnämä oikeudet nyt?", fr_FR="Le tableau de bord requiert des autorisations supplémentaires pour pouvoir\naccéder aux données du téléphone. Souhaitez-vous accorder ces autorisations\nmaintenant?", hr_HR="Dashboard treba dodatna odobrenja kako bi pristupio telefonskim podacima. Želite\nli sada dodijeliti odobrenja?", hu_HU="Az irányítópultnak további jogosultságokra van szüksége a telefonadatok\neléréséhez. Meg szeretnéd most adni ezekez a jogosultságokat?", it_IT="La dashboard richiede ulteriori autorizzazioni per poter accedere ai dati del\ntelefono. Concedere adesso le autorizzazioni necessarie?", nl_NL="Het dashboard vereist extra autorisaties om toegang te krijgen tot de\ntelefoongegevens. Wil je deze autorisaties nu toekennen?", no_NO="Dashbordet mangler noen tillatelser for å få tilgang til telefondata. Vil du gi\ntillatelsene nå?", pl_PL="Pulpit wymaga dodatkowych uprawnień, aby uzyskać dostęp do danych telefonu.\nCzy chcesz przyznać te uprawnienia teraz?", pt_PT="O painel de instrumentos necessita de permissões adicionais para poder aceder aos\ndados do telefone. Queres conceder agora estas permissões?", ro_RO="Dashboard necesită drepturi suplimentare, pentru a putea accesa datele\ntelefonului. Doriţi să acordaţi acum aceste drepturi?", ru_RU="Информационная панель требует дополнительных разрешений для доступа к\nданным телефона. Хотите предоставить эти разрешения сейчас?", sk_SK="Dashboard vyžaduje dodatočné oprávnenia, aby ste mali prístup k údajom telefónu.\nChcete teraz udeliť tieto oprávnenia?", sl_SI="Nadzorna plošča potrebuje dodatna pooblastila za dostop do podatkov iz telefona.\nAli želite zdaj podeliti ta pooblastila?", sr_RS="Za kontrolnu tablu su potrebna dodatna ovlašćenja da bi mogla pristupiti\ntelefonskim podacima. Da li sada želite da dodelite ova ovlašćenja?", sv_SE="Instrumentbrädan behöver ytterligare behörigheter för att komma åt telefondata.\nVill du godkänna dessa behörigheter nu?", tr_TR="Gösterge panelinin telefon verilerine erişebilmesi için ek izinler gerekmektedir. Bu\nizinleri şimdi vermek istiyor musun?", uk_UA="Панель інструментів потребує додаткових дозволів для доступу до даних\nтелефону. Хочете надати ці дозволи зараз?")
texttool_globals_dialog_message___remove_shortcut_message = TextObject(bs_BA="Izbrisati prečicu?", cs_CZ="Smazat zkratku?", da_DK="Slet genvej?", de_DE="Shortcut löschen?", el_GR="Να διαγραφεί η συντόμευση;", en_GB="Delete shortcut?", es_ES="¿Borrar atajo?", fi_FI="Poistetaanko pikavalinta?", fr_FR="Effacer le raccourci?", hr_HR="Izbrisati prečac?", hu_HU="Parancsikon törlése?", it_IT="Cancellare shortcut?", nl_NL="Shortcut wissen?", no_NO="Slette snarvei?", pl_PL="Usunąć skrót?", pt_PT="Apagar atalho?", ro_RO="Ştergere comandă rapidă?", ru_RU="Удалить ярлык?", sk_SK="Shortcut vymazať?", sl_SI="Ali želite izbrisati bližnjico?", sr_RS="Izbrisati prečicu?", sv_SE="Radera genväg?", tr_TR="Kısayol silinsin mi?", uk_UA="Видалити ярлик?")
texttool_globals_dialog_title___phone_request_permissions_title = TextObject(bs_BA="Neophodno ovlaštenje za funkcije telefona", cs_CZ="Autorizace potřebná pro funkce telefonu", da_DK="Autorisation til telefonfunktioner påkrævet", de_DE="Berechtigung für Telefon-Funktionen benötigt", el_GR="Απαιτείται εξουσιοδότηση για λειτουργίες τηλεφώνου", en_GB="Permission for telephone functions required", es_ES="Se precisa permiso para las funciones del teléfono", fi_FI="Tarvitaan oikeus puhelintoimintoja varten", fr_FR="Autorisation requise pour les fonctions du téléphone", hr_HR="Potrebno je odobrenje za telefonske funkcije", hu_HU="Jogosultság szükséges a telefonfunkciók eléréséhez", it_IT="Necessaria autorizzazione per le funzioni del telefono", nl_NL="Autorisatie voor telefoonfuncties vereist", no_NO="Tillatelse kreves for telefonfunksjoner", pl_PL="Wymagane uprawnienie do funkcji telefonu", pt_PT="É necessária permissão para as funções do telefone", ro_RO="Sunt necesare drepturi pentru funcţiile de telefon", ru_RU="Требуется разрешение на функции телефона", sk_SK="Oprávnenie potrebné pre funkcie telefónu", sl_SI="Potrebno je pooblastilo za funkcije telefona", sr_RS="Neophodno ovlašćenje za funkcije telefona", sv_SE="Behörighet för telefonfunktioner krävs", tr_TR="Telefon fonksiyonları için yetkilendirme gerekiyor", uk_UA="Потрібен дозвіл на використання функцій телефону")
