texttool_globals_toast___app_grid__app_moved_to_center_display = TextObject(bs_BA="%1 je zatvoren i trenutno aktivan u MMI.", cs_CZ="%1 je zavřený a aktuálně aktivní v MMI.", da_DK="%1 lukket og p.t. aktiv i MMI.", de_DE="%1 ist geschlossen und aktuell im MMI aktiv.", el_GR="Ο/Η/Το %1 είναι κλειστός/-ή/-ό και αυτή τη\nστιγμή ενεργός/-ή/-ό στο MMI.", en_GB="%1 is closed and is currently active on the MMI.", es_ES="La aplicación %1 está cerrada y activa en el MMI\nactualmente.", fi_FI="%1 on suljettu ja tällä hetkellä aktiivisena\nMMI:ssä.", fr_FR="L'application %1 est fermée et est actuellement\nutilisée dans le MMI.", hr_HR="Aplikacija %1 je zatvorena i trenutačno aktivna u\nMMI-ju.", hu_HU="%1 bezárva, és jelenleg aktív az MMI-ben.", it_IT="L'app %1 è chiusa e al momento è attiva\nnell'MMI.", nl_NL="%1 is gesloten en momenteel actief in MMI.", no_NO="%1 er lukket og brukes nå i MMI.", pl_PL="%1 zamknięta i aktualnie aktywna w MMI.", pt_PT="%1 está fechada e atualmente ativa no MMI.", ro_RO="%1 este închisă şi momentan activă pe MMI.", ru_RU="%1 закрыто и в данный момент активно в MMI.", sk_SK="%1 je zatvorená a momentálne aktívna v MMI.", sl_SI="Aplikacija %1 je zaprta in trenutno aktivna v\nsistemu MMI.", sr_RS="%1 je zatvoren i trenutno aktivan u MMI.", sv_SE="%1 är stängd och aktiv i MMI.", tr_TR="%1 kapalı ve şu anda MMI'da aktif.", uk_UA="%1 закрита і зараз активна в MMI.")
texttool_globals_toast___app_grid__app_moved_to_other_display_toast_no_appname = TextObject(bs_BA="Aplikacija je zatvorena i trenutno aktivna na drugom displeju.", cs_CZ="Aplikace je zavřená a aktuálně aktivní na jiném displeji.", da_DK="Appen er lukket og p.t. aktiv i det andet display.", de_DE="Die App ist geschlossen und aktuell im anderen Display aktiv.", el_GR="Η εφαρμογή είναι κλειστή και αυτή τη στιγμή ενεργή στην άλλη\nοθόνη.", en_GB="The app is closed and is currently active on another display.", es_ES="La aplicación está cerrada y activa en la otra pantalla\nactualmente.", fi_FI="Sovellus on suljettu ja tällä hetkellä aktiivisena toisessa\nnäytössä.", fr_FR="L'application est fermée et est actuellement utilisée sur l'autre\nécran.", hr_HR="Aplikacija je zatvorena i trenutačno aktivna na drugom zaslonu.", hu_HU="Az alkalmazás be van zárva, és jelenleg aktív a másik kijelzőn.", it_IT="L'app è chiusa e al momento è attiva su un altro display.", nl_NL="De app is gesloten en momenteel in het andere display actief.", no_NO="Appen er lukket og brukes nå på det andre displayet.", pl_PL="Aplikacja jest zamknięta i aktualnie aktywna na innym ekranie.", pt_PT="A aplicação está fechada e atualmente está ativa noutro ecrã.", ro_RO="Aplicaţia este închisă şi momentan activă pe celălalt afişaj.", ru_RU="Приложение закрыто и в настоящее время активно на другом\nдисплее.", sk_SK="App je zatvorená a momentálne aktívna na druhom displeji.", sl_SI="Aplikacija je zaprta in trenutno aktivna na drugem zaslonu.", sr_RS="Aplikacija je zatvorena i trenutno aktivna na drugom ekranu.", sv_SE="Appen är stängd och aktiv på den andra displayen.", tr_TR="Uygulama kapalı ve şu anda diğer ekranda aktif.", uk_UA="Програма закрита і зараз активна на іншому дисплеї.")
texttool_globals_toast___app_grid__app_moved_to_passenger_display = TextObject(bs_BA="%1 je zatvoren i trenutno aktivan na MMI displeju\nsuvozača.", cs_CZ="%1 je zavřený a aktuálně aktivní na displeji MMI\nspolujezdce.", da_DK="%1 lukket og p.t. aktiv i MMI-display til\nforsædepassager.", de_DE="%1 ist geschlossen und aktuell im MMI\nBeifahrerdisplay aktiv.", el_GR="Ο/Η/Το %1 είναι κλειστός/-ή/-ό και αυτή τη\nστιγμή ενεργός/-ή/-ό στην οθόνη συνοδηγού του MMI.", en_GB="%1 is closed and is currently active on the MMI\nfront passenger display.", es_ES="La aplicación %1 está cerrada y activa en la\npantalla del MMI del acompañante actualmente.", fi_FI="%1 on suljettu ja tällä hetkellä aktiivisena MMI:n\netumatkustajan näytössä.", fr_FR="L'application %1 est fermée et est actuellement\nutilisée sur l'écran MMI du passager avant.", hr_HR="Aplikacija %1 je zatvorena i trenutačno aktivna\nna suvozačevom zaslonu MMI-ja.", hu_HU="%1 bezárva, és jelenleg aktív az MMI\nutaskijelzőn.", it_IT="L'app %1 è chiusa e al momento è attiva nell'MMI\ndel display passeggero anteriore.", nl_NL="%1 is gesloten en momenteel in het\nMMI-bijrijdersdisplay actief.", no_NO="%1 er lukket og brukes nå på\nMMI-passasjerdisplayet.", pl_PL="%1 jest zamknięta i aktualnie aktywna na ekranie\npasażera w MMI.", pt_PT="%1 está fechada e atualmente está ativa no ecrã\ndo passageiro do MMI.", ro_RO="%1 este închisă şi momentan activă pe afişajul\nMMI pasager faţă.", ru_RU="%1 закрыто и в данный момент активно на\nдисплее MMI переднего пассажира.", sk_SK="%1 je zatvorená a momentálne aktívna v MMI na\ndispleji spolujazdca.", sl_SI="Aplikacija %1 je zaprta in trenutno aktivna na\nsovoznikovem zaslonu sistema MMI.", sr_RS="%1 je zatvoren i trenutno je u MMI displej\nsuvozača aktivan.", sv_SE="%1 är stängd och aktiv på\nMMI-passagerardisplayen.", tr_TR="%1 kapalı ve şu anda MMI ön yolcu ekranında\naktif.", uk_UA="%1 закрита і зараз активна на дисплеї MMI\nпереднього пасажира.")
texttool_globals_toast___car_audi_restrictionreason_ActiveUserAlreadyEnrolled = TextObject(bs_BA="Ograničeno rukovanje u toku vožnje.", cs_CZ="Omezená obsluha během jízdy.", da_DK="Begrænset betjening under kørsel.", de_DE="Eingeschränkte Bedienung während der Fahrt.", el_GR="Περιορισμένος χειρισμός κατά τη διάρκεια της οδήγησης.", en_GB="For your safety, limited operation while driving.", es_ES="Manejo limitado durante la marcha.", fi_FI="Rajoitettu käyttö ajon aikana.", fr_FR="Utilisation restreinte pendant la conduite.", hr_HR="Ograničeno rukovanje tijekom vožnje.", hu_HU="Korlátozott használat menet közben.", it_IT="Utilizzo limitato durante la marcia.", nl_NL="Beperkte bediening tijdens het rijden.", no_NO="Betjening er begrenset under kjøring.", pl_PL="Ograniczona obsługa podczas jazdy.", pt_PT="Acionamento com restrições durante a circulação.", ro_RO="Operare limitată în timpul deplasării.", ru_RU="Во время движения управление ограничено.", sk_SK="Obmedzená obsluha počas jazdy.", sl_SI="Omejeno upravljanje med vožnjo.", sr_RS="Ograničeno rukovanje u toku vožnje.", sv_SE="Begränsad användning under körning.", tr_TR="Sürüş sırasında sınırlı kullanım.", uk_UA="Під час руху керування обмежено.")
texttool_globals_toast___car_audi_restrictionreason_AraHitchBallDetectionFailed = TextObject(bs_BA="Sistem pomoći za prikolicu: Nije bilo moguće locirati kuglastu\nspojnicu. Pogledajte priručnik", cs_CZ="Asistent přívěsu: Kulovou spojku se nepodařilo nalézt. Viz\npalubní kniha", da_DK="Anhængerassistent: Kuglekobling kunne ikke lokaliseres. Se\ninstruktionsbog.", de_DE="Anhängerassistent: Die Kugelkupplung konnte nicht verortet\nwerden. Siehe Bordbuch", el_GR="Σύστ. υποβοήθ. ελιγμ. με ρυμούλκα: Δεν ήτ.εφικτ.ο εντοπ.τ.\nσφαιρ.συνδέσμου (κοτσαδόρου). Δείτε βιβλίο οδηγιών", en_GB="Trailer assist: unable to detect ball-head coupling. See owner's\nmanual", es_ES="Asistente del remolque: No se ha localizado el acoplamiento para\nla bola. Ver Manual", fi_FI="Perävaunuavustin: kuulakytkintä ei pystytty paikantamaan. Ks.\nkäyttöohjekirja.", fr_FR="Assistant de manœuvre avec remorque: la boule d'attelage n'a\npas pu être localisée. Voir Notice d'Utilisation", hr_HR="Potpora pri parkiranju: spojka kuke za vuču nije locirana. Vidi\npriručnu literaturu", hu_HU="Utánfutó-vonóberendezés: a vonófej helyzetét nem lehetett\nmeghatározni. Lásd a fedélzeti irodalmat", it_IT="Assistenza rimorchio: non è stato possibile localizzare il giunto a\nsfera. Vedi libretto", nl_NL="Aanhangwagenassistent: de kogelkoppeling kon niet worden\ngevonden. Zie instructieboekje", no_NO="Tilhengerassistent: Kan ikke lokalisere kulekoblingen. Se\ninstruksjonsboken", pl_PL="Asystent jazdy z przyczepą: nie można zlokalizować zaczepu\nkulowego. Patrz instrukcja obsługi", pt_PT="Assistente de reboque: A esfera de engate não pode ser\nlocalizada. Ver Manual de Bordo", ro_RO="Asistent remorcă: nu s-a putut localiza cupla sferică. Consultaţi\nmapa de bord", ru_RU="Ассистент прицепа: не удалось обнаружить шаровую муфту.\nСм. руководство по эксплуатации", sk_SK="Asistent pre príves: guľovú spojku sa nepodarilo lokalizovať.\nPozrite palubnú dokumentáciu", sl_SI="Asistenca za prikolico: vlečne kljuke ni bilo mogoče locirati. Glejte\nNavodila", sr_RS="Asistencija prikolice: Nije bilo moguće locirati kuglastu spojnicu.\nVideti priručnu literaturu", sv_SE="Släpvagnsassistans: Kulkopplingen kunde inte lokaliseras. Se\ninstruktionsboken", tr_TR="Römork asistanı: Bilyeli bağlantının yeri bulunamadı. Kullanım\nkılavuzuna bakın", uk_UA="Асистент маневрування з причепом: кулькову муфту не\nвдалося встановити. Див. бортову документацію")
texttool_globals_toast___car_audi_restrictionreason_AraHitchBallPositionUnknown = TextObject(bs_BA="Sistem pomoći za prikolicu: Lociranje kuglaste spojnice je još u\ntoku. Pogledajte priručnik", cs_CZ="Asistent přívěsu: Kulová spojka se stále vyhledává. Vy můžete\nasistovat. Viz palubní kniha", da_DK="Anhængerassistent: Kuglekobling lokaliseres stadig. Du kan\nhjælpe. Se instruktionsbog.", de_DE="Anhängerassistent: Die Kugelkupplung wird noch verortet. Du\nkannst unterstützen. Siehe Bordbuch", el_GR="Σύστ.υποβ.ελιγμ.με ρυμούλκα: Ο εντοπ.τ.σφαιρ.συνδέσμου\n(κοτσαδ.) είναι ακόμη σε εξέλιξη. Δείτε βιβλίο οδηγιών", en_GB="Trailer assist: detecting ball-head coupling. You can also help.\nSee owner's manual", es_ES="Asistente del remolque: buscando el acoplamiento para la bola.\n¿Quiere ayudar? Ver Manual", fi_FI="Perävaunuavustin: kuulakytkintä paikannetaan edelleen. Voit\navustaa. Ks. käyttöohjekirja.", fr_FR="Assistant de manœuvre avec remorque: localisation de la boule\nd'attelage encore en cours. Vous pouvez venir en aide. Voir Notice", hr_HR="Potpora pri parkiranju: spojka kuke za vuču još se locira. Možete\npružiti potporu. Vidi priručnu literaturu", hu_HU="Utánfutó-vonóberendezés: még folyamatban van a vonófej\nhelyzetének meghatározása. Lásd a fedélzeti irodalmat", it_IT="Assistenza rimorchio: la localizzazione del giunto a sfera è\nancora in corso. È possibile intervenire per facilitare l'operazione.", nl_NL="Aanhangwagenassistent: de kogelkoppeling wordt nog gezocht.\nU kunt helpen. Zie instructieboekje", no_NO="Tilhengerassistent: Lokaliserer kulekoblingen. Du kan hjelpe. Se\ninstruksjonsboken", pl_PL="Asystent jazdy z przyczepą: trwa lokalizowanie zaczepu\nkulowego. Możesz w tym pomóc. Patrz instrukcja obsługi", pt_PT="Assistente de reboque: A esfera de engate ainda será localizada.\nPode dar uma ajuda. Ver Manual de Bordo", ro_RO="Asistent remorcă: încă se localizează cupla sferică. Puteţi asista.\nConsultaţi mapa de bord", ru_RU="Ассистент прицепа: шаровая муфта еще размещается. Вы\nможете оказать поддержку. См. руководство по эксплуатации", sk_SK="Asistent pre príves: guľovú spojku sa stále nepodarilo lokalizovať.\nProces môžete podporiť. Pozrite palubnú dokumentáciu", sl_SI="Asistenca za prikolico: vlečna kljuka bo še locirana. Lahko\npomagate. Glejte Navodila", sr_RS="Asistencija prikolice: Lociranje kuglaste spojnice je još u toku.\nMožete pružiti podršku. Videti priručnu literaturu", sv_SE="Släpvagnsassistans: Kulkopplingen kunde inte lokaliseras. Du\nkan ge stöd. Se instruktionsboken", tr_TR="Römork asistanı: Bilyeli bağlantının yeri halen belirleniyor.\nDestekleyebilirsiniz. Kullanım kılavuzuna bakın", uk_UA="Асистент маневр. з причепом: кулькова муфта все ще\nрозташовуєтеся. Можете над. підтримку. Див. борт. док.")
texttool_globals_toast___car_audi_restrictionreason_AuthWithMobileDeviceKeyRequired = TextObject(bs_BA="Ograničeno rukovanje u toku vožnje.", cs_CZ="Omezená obsluha během jízdy.", da_DK="Begrænset betjening under kørsel.", de_DE="Eingeschränkte Bedienung während der Fahrt.", el_GR="Περιορισμένος χειρισμός κατά τη διάρκεια της οδήγησης.", en_GB="For your safety, limited operation while driving.", es_ES="Manejo limitado durante la marcha.", fi_FI="Rajoitettu käyttö ajon aikana.", fr_FR="Utilisation restreinte pendant la conduite.", hr_HR="Ograničeno rukovanje tijekom vožnje.", hu_HU="Korlátozott használat menet közben.", it_IT="Utilizzo limitato durante la marcia.", nl_NL="Beperkte bediening tijdens het rijden.", no_NO="Betjening er begrenset under kjøring.", pl_PL="Ograniczona obsługa podczas jazdy.", pt_PT="Acionamento com restrições durante a circulação.", ro_RO="Operare limitată în timpul deplasării.", ru_RU="Во время движения управление ограничено.", sk_SK="Obmedzená obsluha počas jazdy.", sl_SI="Omejeno upravljanje med vožnjo.", sr_RS="Ograničeno rukovanje u toku vožnje.", sv_SE="Begränsad användning under körning.", tr_TR="Sürüş sırasında sınırlı kullanım.", uk_UA="Під час руху керування обмежено.")
texttool_globals_toast___car_audi_restrictionreason_AuthWithPhysicalKeyRequired = TextObject(bs_BA="Funkcija se ne može deaktivirati, jer je vozilo uključeno pomoću\ndigitalnog ključa ili kartice ključa.", cs_CZ="Funkci nelze deaktivovat, protože vozidlo bylo zapnuto\ndigitálním klíčkem nebo kartou.", da_DK="Funktionen kan ikke deaktiveres, da bilen blev startet med en\ndigital nøgle eller et nøglekort.", de_DE="Funktion kann nicht deaktiviert werden. Fahrzeug wurde mit\ndigitalem Schlüssel oder Schlüsselkarte eingeschaltet.", el_GR="Η λειτουργία δεν μπορεί να απενεργοποιηθεί, διότι το όχημα\nενεργοποιήθηκε με ένα ψηφιακό κλειδί ή με μια κάρτα κωδικού.", en_GB="The function cannot be deactivated because the vehicle was\nswitched on using a digital key or a key card.", es_ES="La función no se puede desactivar porque el vehículo se ha\nencendido con una llave digital o con una tarjeta llave.", fi_FI="Toimintoa ei voi deaktivoida, sillä auto on käynnistetty\ndigitaalisella avaimella tai avainkortilla.", fr_FR="La fonction ne peut pas être désactivée car l'alimentation du\nvéhicule a été établie avec une clé numériq. ou une carte clé.", hr_HR="Funkcija se ne može deaktivirati budući je vozilo uključeno\ndigitalnim ili kartičnim ključem.", hu_HU="A funkció nem kapcsolható ki, mivel a járművet digitális kulccsal\nvagy kulcskártyával indították be.", it_IT="Non è possibile disattivare la funzione, perché la vettura è stata\navviata con una chiave digitale o una scheda chiave.", nl_NL="De functie kan niet worden gedeactiveerd, omdat het voertuig\nmet een digitale sleutel of een sleutelkaart is ingeschakeld.", no_NO="Kan ikke deaktivere funksjonen fordi bilen ble slått på med en\ndigital nøkkel eller et nøkkelkort.", pl_PL="Funkcji nie można wyłączyć, ponieważ pojazd został włączony za\npomocą kluczyka cyfrowego lub karty kluczyka.", pt_PT="A função não pode ser desativada, pois o veículo foi ligado com\numa chave digital ou um cartão chave.", ro_RO="Funcţia nu poate fi dezactivată, deoarece autovehiculul a fost\npornit cu o cheie digitală sau cu un card de acces.", ru_RU="Функция не может быть отключена, поскольку автомобиль был\nвключен с помощью цифрового ключа или ключ-карты.", sk_SK="Funkciu nie je možné deaktivovať, pretože vozidlo bolo zapnuté\ndigitálnym kľúčom alebo kartou s kľúčom.", sl_SI="Funkcije ni mogoče deaktivirati, ker je bilo vozilo vključeno z\ndigitalnim ključem ali kontaktno kartico.", sr_RS="Funkcija ne može da se deaktivira, jer je vozilo uključeno pomoću\ndigitalnog ključa ili ključ-kartice.", sv_SE="Funktionen kan inte avaktiveras eftersom fordonet startades\nmed en digital nyckel eller ett nyckelkort.", tr_TR="Fonksiyon devre dışı bırakılamaz, çünkü araç bir dijital anahtar\nveya bir anahtar kartı ile açılmış.", uk_UA="Функція не може бути відключена, оскільки автомобіль був\nувімкнений за допомогою цифрового ключа або ключ-карти.")
